// 1871. Jump Game VII

package problems

import "fmt"

func Problem_1871() {
	s := ""
	minJump := 1
	maxJump := 49999
	fmt.Println(canReach(s, minJump, maxJump))
}

func canReach(s string, minJump int, maxJump int) bool {
	n := len(s)
	v := make([]bool, n)
	v[0] = true
	c := 1
	for i := minJump; i < n; i++ {
		if s[i] == '0' {
			v[i] = c > 0
		}
		if v[i-minJump+1] {
			c++
		}
		if i >= maxJump && v[i-maxJump] {
			c--
		}
	}
	return v[n-1]
}
